function scheduleRecord(schedule) {
  return schedule.reduce((acc, g) => {
    if (g.teamScore == null || g.oppScore == null) return acc;
    if (g.teamScore > g.oppScore) acc.wins += 1;
    else if (g.teamScore < g.oppScore) acc.losses += 1;
    else acc.ties += 1;
    return acc;
  }, { wins: 0, losses: 0, ties: 0 });
}

function scheduleNextGame(schedule) {
  return schedule.find((g) => g.teamScore == null || g.oppScore == null) || null;
}

function scheduleRecentResults(schedule, n = 4) {
  return schedule.filter((g) => g.teamScore != null && g.oppScore != null).slice(-n).reverse();
}

